def _has_fusion_timeline_scope(p: Dict[str, Any]) -> bool:
    return bool(p.get("clip_id") or p.get("timeline_item_id") or "timeline_item" in p)

def _get_timeline_item_for_fusion(p: Dict[str, Any]):
    """Resolve optional timeline scope for fusion_comp."""
    if not _has_fusion_timeline_scope(p):
        return None, None

    timeline_item = p.get("timeline_item")
    if "timeline_item" in p and not isinstance(timeline_item, dict):
        return None, _err("timeline_item must be an object with track_type, track_index, and item_index")

    _, tl, err = _get_tl()
    if err:
        return None, err

    timeline_item_id = p.get("clip_id") or p.get("timeline_item_id")
    if timeline_item_id:
        item = _find_timeline_item_by_id(tl, timeline_item_id)
        if not item:
            return None, _err(f"No timeline item with clip_id/timeline_item_id={timeline_item_id!r}")
        return item, None

    query = dict(timeline_item)
    query.setdefault("track_type", "video")
    _, item, item_err = _get_item(query)
    if item_err:
        return None, item_err
    return item, None

def _get_fusion_comp_on_timeline_item(item, p: Dict[str, Any]):
    """Get a Fusion composition on a TimelineItem."""
    try:
        comp_count = int(item.GetFusionCompCount() or 0)
    except Exception as exc:
        return None, _err(f"GetFusionCompCount failed: {exc}")
    if comp_count < 1:
        return None, _err("Timeline item has no Fusion compositions")

    comp_name = p.get("comp_name")
    if comp_name:
        comp = item.GetFusionCompByName(str(comp_name))
        if not comp:
            return None, _err(f"No Fusion comp named {comp_name!r} on this timeline item")
        return comp, None

    try:
        comp_index = int(p.get("comp_index", 1))
    except (TypeError, ValueError):
        return None, _err("comp_index must be a 1-based integer")
    if comp_index < 1 or comp_index > comp_count:
        return None, _err(f"No Fusion comp at comp_index={comp_index}; item has {comp_count} comp(s)")

    comp = item.GetFusionCompByIndex(comp_index)
    if not comp:
        return None, _err(f"GetFusionCompByIndex({comp_index}) returned no composition")
    return comp, None

def _resolve_fusion_comp(p: Dict[str, Any], require_timeline_scope: bool = False):
    """Resolve a Fusion comp from timeline scope or the active Fusion page comp."""
    if require_timeline_scope and not _has_fusion_timeline_scope(p):
        return None, _err(
            "Timeline scope is required: pass clip_id, timeline_item_id, "
            "or timeline_item={track_type, track_index, item_index}"
        )

    r = get_resolve()
    if not r:
        return None, _err("Not connected to DaVinci Resolve. Is Resolve running?")

    item, item_err = _get_timeline_item_for_fusion(p)
    if item_err:
        return None, item_err
    if item is not None:
        return _get_fusion_comp_on_timeline_item(item, p)

    fusion = r.Fusion()
    if not fusion:
        return None, _err("Fusion not available — switch to the Fusion page first")
    comp = fusion.GetCurrentComp()
    if not comp:
        return None, _err(
            "No active Fusion composition. Open a clip in the Fusion page first, "
            "or pass clip_id, timeline_item_id, or timeline_item={track_type, track_index, item_index} "
            "with optional comp_name or comp_index."
        )
    return comp, None

@mcp.tool()
@_destructive_op("timeline_item_fusion")
def timeline_item_fusion(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Fusion composition operations on timeline items. Identify by track_type, track_index, item_index (item_index is 0-BASED: 0 = first clip; track_index is 1-based).

    Actions:
      add_comp(...) -> {success}
      get_comp_count(...) -> {count}
      get_comp_names(...) -> {names}
      get_comp_by_name(name, ...) -> {available}
      get_comp_by_index(index, ...) -> {available}
      export_comp(path, index, ...) -> {success}
      import_comp(path, ...) -> {success}
      delete_comp(name, ...) -> {success}
      load_comp(name, ...) -> {success}
      rename_comp(old_name, new_name, ...) -> {success}
      get_cache_enabled(...) -> {enabled}  — Fusion output cache status
      set_cache(value, ...) -> {success}  — value: "Auto", "On", or "Off"

    Default: track_type="video", track_index=1, item_index=0
    """
    p = params or {}
    _, item, err = _get_item(p)
    if err:
        return err

    if action == "add_comp":
        comp = item.AddFusionComp()
        return _ok() if comp else _err("Failed to add Fusion comp")
    elif action == "get_comp_count":
        return {"count": item.GetFusionCompCount()}
    elif action == "get_comp_names":
        return {"names": _ser(item.GetFusionCompNameList())}
    elif action == "get_comp_by_name":
        comp = item.GetFusionCompByName(p["name"])
        return {"available": comp is not None}
    elif action == "get_comp_by_index":
        comp = item.GetFusionCompByIndex(p["index"])
        return {"available": comp is not None}
    elif action == "export_comp":
        return {"success": bool(item.ExportFusionComp(p["path"], p["index"]))}
    elif action == "import_comp":
        comp = item.ImportFusionComp(p["path"])
        return _ok() if comp else _err("Failed to import comp")
    elif action == "delete_comp":
        return {"success": bool(item.DeleteFusionCompByName(p["name"]))}
    elif action == "load_comp":
        comp = item.LoadFusionCompByName(p["name"])
        return _ok() if comp else _err("Failed to load comp")
    elif action == "rename_comp":
        return {"success": bool(item.RenameFusionCompByName(p["old_name"], p["new_name"]))}
    elif action == "get_cache_enabled":
        return {"enabled": item.GetIsFusionOutputCacheEnabled()}
    elif action == "set_cache":
        return {"success": bool(item.SetFusionOutputCache(p["value"]))}
    return _unknown(action, ["add_comp","get_comp_count","get_comp_names","get_comp_by_name","get_comp_by_index","export_comp","import_comp","delete_comp","load_comp","rename_comp","get_cache_enabled","set_cache"])

def _find_fusion_group(comp, group_name: str):
    tool = comp.FindTool(group_name)
    if tool:
        attrs = tool.GetAttrs() or {}
        if attrs.get("TOOLS_RegID") == "GroupOperator":
            return tool
    tool_list = comp.GetToolList(False, "GroupOperator") or {}
    for idx in tool_list:
        candidate = tool_list[idx]
        attrs = candidate.GetAttrs() or {}
        if attrs.get("TOOLS_Name") == group_name:
            return candidate
    return None

def _resolve_setting_path(p: Dict[str, Any], key: str = "path") -> Tuple[Optional[str], Optional[Dict[str, Any]]]:
    raw = p.get(key)
    if not raw or not str(raw).strip():
        return None, _err(f"{key} is required")
    return os.path.abspath(str(raw)), None

def _fusion_group_advisory(include: bool) -> Dict[str, Any]:
    if not include:
        return {}
    return {
        "guardrails": list(FUSION_GROUP_GUARDRAILS),
        "commit_checklist": list(FUSION_COMMIT_CHECKLIST),
    }

def _fusion_group_settings_export(comp, p: Dict[str, Any]) -> Dict[str, Any]:
    group_name = p.get("group_name")
    if not group_name:
        return _err("group_name is required")
    path, path_err = _resolve_setting_path(p)
    if path_err:
        return path_err
    group = _find_fusion_group(comp, str(group_name))
    if not group:
        return _err(f"GroupOperator {group_name!r} not found in comp")
    os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
    try:
        group.SaveSettings(path)
    except Exception as exc:
        return _err(f"SaveSettings failed: {exc}")
    if not os.path.isfile(path):
        return _err(f"SaveSettings did not create file at {path!r}")
    try:
        parsed = parse_setting_file(path, group_name=str(group_name))
    except Exception as exc:
        return {
            "success": True,
            "path": path,
            "group_name": group_name,
            "parse_warning": f"saved, but summary parse failed: {exc}",
            **_fusion_group_advisory(p.get("include_advisory", False)),
        }
    return {
        "success": True,
        "path": path,
        "group_name": group_name,
        "published_inputs": parsed["published_inputs"],
        "input_count": parsed["input_count"],
        **_fusion_group_advisory(p.get("include_advisory", False)),
    }

def _fusion_group_settings_splice_inputs(p: Dict[str, Any]) -> Dict[str, Any]:
    source_path, src_err = _resolve_setting_path(p, "source_path")
    if src_err:
        return src_err
    if not os.path.isfile(source_path):
        return _err(f"source_path not found: {source_path}")
    template_path, tpl_err = _resolve_setting_path(p, "template_path")
    if tpl_err:
        return tpl_err
    if not os.path.isfile(template_path):
        return _err(f"template_path not found: {template_path}")
    dest_path = p.get("dest_path")
    if dest_path:
        dest_path = os.path.abspath(str(dest_path))
    else:
        root, ext = os.path.splitext(source_path)
        dest_path = f"{root}.patched{ext or '.setting'}"
    try:
        summary = splice_inputs_block(
            source_path,
            template_path,
            dest_path,
            source_group_name=p.get("source_group_name") or p.get("group_name"),
            template_group_name=p.get("template_group_name"),
        )
    except Exception as exc:
        return _err(f"splice failed: {exc}")
    return {
        "success": True,
        "dest_path": summary["dest_path"],
        "summary": summary,
        **_fusion_group_advisory(p.get("include_advisory", False)),
    }

def _fusion_group_settings_load(comp, p: Dict[str, Any]) -> Dict[str, Any]:
    group_name = p.get("group_name")
    if not group_name:
        return _err("group_name is required")
    settings_path, path_err = _resolve_setting_path(p, "settings_path")
    if path_err:
        return path_err
    if not os.path.isfile(settings_path):
        return _err(f"settings_path not found: {settings_path}")
    group = _find_fusion_group(comp, str(group_name))
    if not group:
        return _err(f"GroupOperator {group_name!r} not found in comp")
    backup_path = p.get("backup_path")
    if backup_path:
        backup_path = os.path.abspath(str(backup_path))
    else:
        backup_path = default_backup_path(settings_path)
    try:
        os.makedirs(os.path.dirname(backup_path) or ".", exist_ok=True)
        group.SaveSettings(backup_path)
    except Exception as exc:
        return _err(f"backup SaveSettings failed: {exc}")

    undo_name = p.get("undo_name", f"MCP group_settings_load {group_name}")
    undo_started = False
    keep_undo = False
    error_message: Optional[str] = None
    try:
        try:
            comp.StartUndo(undo_name)
            undo_started = True
        except Exception:
            undo_started = False
        comp.Lock()
        try:
            group.LoadSettings(settings_path)
            keep_undo = True
        finally:
            comp.Unlock()
    except Exception as exc:
        error_message = str(exc)
    finally:
        if undo_started:
            try:
                comp.EndUndo(keep_undo)
            except Exception:
                pass

    if error_message is not None:
        return _err(
            f"LoadSettings failed: {error_message}",
            remediation=f"Group state preserved by backup at {backup_path}",
        )
    return {
        "success": True,
        "group_name": group_name,
        "settings_path": settings_path,
        "backup_path": backup_path,
        "warning": (
            "Group preserved. If Edit Controls don't refresh, select the group in "
            "Fusion and use UI Load Settings to remap InstanceInput order."
        ),
        **_fusion_group_advisory(p.get("include_advisory", False)),
    }

def _fusion_comp_bulk_set_expressions(p: Dict[str, Any]) -> Dict[str, Any]:
    ops = p.get("ops")
    if not isinstance(ops, list) or not ops:
        return _err(
            "bulk_set_expressions requires params.ops: non-empty list of objects. "
            "Each op must include tool_name, input_name, expression, and a timeline scope: "
            "clip_id, timeline_item_id, or timeline_item={track_type, track_index, item_index}. "
            "Optional per-op: comp_name, comp_index, time, undo_name."
        )
    results: List[Dict[str, Any]] = []
    for index, op in enumerate(ops):
        if not isinstance(op, dict):
            results.append({"index": index, "error": "op must be an object"})
            continue
        if not _has_fusion_timeline_scope(op):
            results.append({"index": index, "error": "timeline scope is required for bulk_set_expressions"})
            continue
        missing = [key for key in ("tool_name", "input_name", "expression") if key not in op]
        if missing:
            results.append({"index": index, "error": f"missing required field(s): {', '.join(missing)}"})
            continue
        comp, comp_err = _resolve_fusion_comp(op, require_timeline_scope=True)
        if comp_err:
            results.append({"index": index, "error": comp_err.get("error", str(comp_err))})
            continue
        tool = comp.FindTool(op["tool_name"])
        if not tool:
            results.append({"index": index, "error": f"Tool {op['tool_name']!r} not found"})
            continue
        undo_name = op.get("undo_name", f"MCP bulk_set_expressions #{index}")
        undo_started = False
        keep_undo = False
        error_message: Optional[str] = None
        try:
            try:
                comp.StartUndo(undo_name)
                undo_started = True
            except Exception:
                undo_started = False
            comp.Lock()
            try:
                time = op.get("time", 0)
                inp = tool[op["input_name"]]
                if not inp:
                    raise ValueError(f"Input {op['input_name']!r} not found on {op['tool_name']!r}")
                inp.SetExpression(str(op["expression"]), time)
                keep_undo = True
            finally:
                comp.Unlock()
        except Exception as exc:
            error_message = str(exc)
        finally:
            if undo_started:
                try:
                    comp.EndUndo(keep_undo)
                except Exception:
                    pass
        if error_message is not None:
            results.append({"index": index, "error": error_message})
        elif keep_undo:
            results.append({"index": index, "success": True, "expression": op["expression"]})
    return {"results": results, "op_count": len(ops)}

def _fusion_probe_group_published_inputs(comp, p: Dict[str, Any]) -> Dict[str, Any]:
    group_name = p.get("group_name")
    if not group_name:
        return _err("group_name is required")
    group = _find_fusion_group(comp, str(group_name))
    if not group:
        return _err(f"GroupOperator {group_name!r} not found in comp")
    max_inputs = p.get("max_inputs", 32)
    try:
        max_inputs = int(max_inputs)
    except (TypeError, ValueError):
        max_inputs = 32
    time = p.get("time", 0)
    live_inputs: List[Dict[str, Any]] = []
    for index in range(1, max_inputs + 1):
        slot = f"Input{index}"
        try:
            inp = group[slot]
        except Exception:
            break
        if not inp:
            break
        row: Dict[str, Any] = {"slot": slot}
        try:
            attrs = inp.GetAttrs() or {}
            row["name"] = attrs.get("INPS_Name", "")
            row["type"] = attrs.get("INPS_DataType", "")
        except Exception:
            pass
        try:
            row["value"] = _ser(inp[time])
        except Exception as exc:
            row["value_error"] = str(exc)
        try:
            row["expression"] = inp.GetExpression(time)
        except Exception:
            row["expression"] = None
        live_inputs.append(row)

    file_summary: Optional[Dict[str, Any]] = None
    settings_path = p.get("settings_path")
    if settings_path and os.path.isfile(str(settings_path)):
        try:
            file_summary = parse_setting_file(str(settings_path), group_name=str(group_name))
        except Exception as exc:
            file_summary = {"error": str(exc)}

    return {
        "group_name": group_name,
        "live_inputs": live_inputs,
        "live_input_count": len(live_inputs),
        "file_summary": file_summary,
        **_fusion_group_advisory(p.get("include_advisory", False)),
    }

def _fusion_comp_bulk_set_inputs(p: Dict[str, Any]) -> Dict[str, Any]:
    """Apply set_input across many explicitly scoped timeline-item Fusion comps."""
    ops = p.get("ops")
    if not isinstance(ops, list) or not ops:
        return _err(
            "bulk_set_inputs requires params.ops: non-empty list of objects. "
            "Each op must include tool_name, input_name, value, and a timeline scope: "
            "clip_id, timeline_item_id, or timeline_item={track_type, track_index, item_index}. "
            "Optional per-op: comp_name, comp_index, time, undo_name."
        )

    results: List[Dict[str, Any]] = []
    for index, op in enumerate(ops):
        if not isinstance(op, dict):
            results.append({"index": index, "error": "op must be an object"})
            continue
        if not _has_fusion_timeline_scope(op):
            results.append({
                "index": index,
                "error": "timeline scope is required for bulk_set_inputs",
            })
            continue
        missing = [key for key in ("tool_name", "input_name", "value") if key not in op]
        if missing:
            results.append({"index": index, "error": f"missing required field(s): {', '.join(missing)}"})
            continue

        comp, comp_err = _resolve_fusion_comp(op, require_timeline_scope=True)
        if comp_err:
            results.append({"index": index, "error": comp_err.get("error", str(comp_err))})
            continue

        tool = comp.FindTool(op["tool_name"])
        if not tool:
            results.append({"index": index, "error": f"Tool {op['tool_name']!r} not found"})
            continue

        undo_name = op.get("undo_name", f"MCP bulk_set_inputs #{index}")
        undo_started = False
        keep_undo = False
        error_message = None
        try:
            try:
                comp.StartUndo(undo_name)
                undo_started = True
            except Exception:
                undo_started = False
            comp.Lock()
            try:
                if "time" in op:
                    tool.SetInput(op["input_name"], op["value"], op["time"])
                else:
                    tool.SetInput(op["input_name"], op["value"])
                keep_undo = True
            finally:
                comp.Unlock()
        except Exception as exc:
            error_message = str(exc)
        finally:
            if undo_started:
                try:
                    comp.EndUndo(keep_undo)
                except Exception:
                    pass
        if error_message is not None:
            results.append({"index": index, "error": error_message})
        elif keep_undo:
            results.append({"index": index, "success": True})

    return {"results": results, "op_count": len(ops)}

def _fusion_tool_summary(tool, *, include_io=False):
    attrs = tool.GetAttrs() or {}
    out = {
        "name": attrs.get("TOOLS_Name", ""),
        "type": attrs.get("TOOLS_RegID", ""),
        "attrs": _ser(attrs),
    }
    if include_io:
        inputs = []
        input_list = tool.GetInputList() or {}
        for idx in input_list:
            inp = input_list[idx]
            inp_attrs = inp.GetAttrs() or {}
            connected = inp.GetConnectedOutput()
            connected_to = None
            if connected:
                conn_tool = connected.GetTool()
                if conn_tool:
                    connected_to = (conn_tool.GetAttrs() or {}).get("TOOLS_Name", "")
            inputs.append(
                {
                    "name": inp_attrs.get("INPS_Name", ""),
                    "id": inp_attrs.get("INPS_ID", ""),
                    "type": inp_attrs.get("INPS_DataType", ""),
                    "connected_to": connected_to,
                }
            )
        outputs = []
        output_list = tool.GetOutputList() or {}
        for idx in output_list:
            output = output_list[idx]
            output_attrs = output.GetAttrs() or {}
            outputs.append(
                {
                    "name": output_attrs.get("OUTS_Name", ""),
                    "id": output_attrs.get("OUTS_ID", ""),
                    "type": output_attrs.get("OUTS_DataType", ""),
                }
            )
        out["inputs"] = inputs
        out["outputs"] = outputs
    return out

def _fusion_comp_snapshot(comp, p: Dict[str, Any]):
    attrs = comp.GetAttrs() or {}
    tools = []
    tool_list = comp.GetToolList() or {}
    max_tools = p.get("max_tools", 20)
    try:
        max_tools = int(max_tools)
    except (TypeError, ValueError):
        max_tools = 20
    include_io = bool(p.get("include_io", False))
    for idx in list(tool_list)[:max_tools]:
        tools.append(_fusion_tool_summary(tool_list[idx], include_io=include_io))
    return {
        "name": attrs.get("COMPS_Name", ""),
        "tool_count": len(tool_list),
        "attrs": _ser(attrs),
        "tools": tools,
    }

def _fusion_graph_capabilities(comp):
    attrs = comp.GetAttrs() or {}
    return {
        "comp": {
            "name": attrs.get("COMPS_Name", ""),
            "tool_count": len(comp.GetToolList() or {}),
        },
        "common_tools": list(_COMMON_FUSION_TOOLS),
        "supported": [
            "timeline-item Fusion comp targeting",
            "tool list and attr inspection",
            "tool input/output inspection",
            "safe tool creation",
            "safe batch input writes with optional readback",
            "validated tool connections",
            "timeline item comp import/export through timeline_item_fusion",
        ],
        "boundaries": [
            "Tool availability varies by Resolve/Fusion build.",
            "Some inputs are write-only or coerce values without reliable readback.",
            "Fusion page current comp and timeline-item comp scopes are different.",
            "Comp rendering requires a valid graph and can be page/state dependent.",
        ],
    }

def _safe_add_fusion_tool(comp, p: Dict[str, Any]):
    tool_type = p.get("tool_type")
    if not tool_type:
        return _err("tool_type is required")
    if p.get("dry_run"):
        return _ok(tool_type=tool_type, name=p.get("name"), would_add=True)
    comp.Lock()
    try:
        tool = comp.AddTool(tool_type, p.get("x", -1), p.get("y", -1))
        if not tool:
            return _err(f"Failed to add tool '{tool_type}'. Check the tool ID is valid.")
        if p.get("name"):
            tool.SetAttrs({"TOOLS_Name": p["name"]})
        return _ok(tool=_fusion_tool_summary(tool, include_io=p.get("include_io", True)))
    finally:
        comp.Unlock()

def _probe_fusion_tool(comp, p: Dict[str, Any]):
    name = p.get("tool_name") or p.get("name")
    if not name:
        return _err("tool_name is required")
    tool = comp.FindTool(name)
    if not tool:
        return {"found": False, "tool_name": name}
    return {"found": True, "tool": _fusion_tool_summary(tool, include_io=p.get("include_io", True))}

def _safe_set_fusion_inputs(comp, p: Dict[str, Any]):
    tool_name = p.get("tool_name")
    inputs = p.get("inputs")
    if not tool_name:
        return _err("tool_name is required")
    if not isinstance(inputs, dict) or not inputs:
        return _err("inputs must be a non-empty object")
    tool = comp.FindTool(tool_name)
    if not tool:
        return _err(f"Tool '{tool_name}' not found")
    if p.get("dry_run"):
        return _ok(tool_name=tool_name, inputs=inputs, would_set=True)
    results = {}
    comp.Lock()
    try:
        for input_name, value in inputs.items():
            try:
                if "time" in p:
                    tool.SetInput(input_name, value, p["time"])
                else:
                    tool.SetInput(input_name, value)
                row = {"success": True}
                if p.get("readback", True):
                    try:
                        row["value"] = _ser(tool.GetInput(input_name, p["time"])) if "time" in p else _ser(tool.GetInput(input_name))
                    except Exception as exc:
                        row["readback_error"] = str(exc)
                results[input_name] = row
            except Exception as exc:
                results[input_name] = {"success": False, "error": str(exc)}
    finally:
        comp.Unlock()
    return {"success": all(row.get("success") for row in results.values()), "tool_name": tool_name, "results": results}

def _safe_connect_fusion_tools(comp, p: Dict[str, Any]):
    target_name = p.get("target_tool")
    source_name = p.get("source_tool")
    input_name = p.get("input_name")
    if not target_name or not source_name or not input_name:
        return _err("target_tool, source_tool, and input_name are required")
    target = comp.FindTool(target_name)
    if not target:
        return _err(f"Target tool '{target_name}' not found")
    source = comp.FindTool(source_name)
    if not source:
        return _err(f"Source tool '{source_name}' not found")
    if p.get("dry_run"):
        return _ok(target_tool=target_name, source_tool=source_name, input_name=input_name, would_connect=True)
    comp.Lock()
    try:
        success = bool(target.ConnectInput(input_name, source))
    finally:
        comp.Unlock()
    return {"success": success, "target_tool": target_name, "source_tool": source_name, "input_name": input_name}

def _fusion_boundary_report(comp, p: Dict[str, Any]):
    return {
        "capabilities": _fusion_graph_capabilities(comp),
        "composition": _fusion_comp_snapshot(comp, {**p, "include_io": p.get("include_io", True)}),
    }

def _parse_pos(raw):
    """Normalize a FlowView position return into (x, y) floats, or None.

    Depending on the bridge, position reads come back as a 1-indexed Lua table,
    a dict ({1: x, 2: y} / {"x": .., "y": ..}), or an (x, y) tuple/list. Be
    liberal in what we accept.
    """
    if raw is None:
        return None
    if isinstance(raw, dict):
        for ka, kb in ((1, 2), ("1", "2"), ("x", "y"), ("X", "Y")):
            if ka in raw and kb in raw:
                try:
                    return float(raw[ka]), float(raw[kb])
                except (TypeError, ValueError):
                    return None
        vals = list(raw.values())
        if len(vals) >= 2:
            try:
                return float(vals[0]), float(vals[1])
            except (TypeError, ValueError):
                return None
        return None
    if isinstance(raw, (list, tuple)):
        if len(raw) >= 2:
            try:
                return float(raw[0]), float(raw[1])
            except (TypeError, ValueError):
                return None
        return None
    # Lua table object with numeric indexing.
    try:
        return float(raw[1]), float(raw[2])
    except Exception:
        return None

def _fusion_flow_view(comp):
    """Return the comp's FlowView (node-graph canvas), or None if unavailable."""
    try:
        cf = comp.CurrentFrame
        if cf is None:
            return None
        return cf.FlowView
    except Exception:
        return None

def _iter_fusion_tools(comp):
    """Yield (tool_name, tool) for every tool in the comp."""
    tools = comp.GetToolList() or {}
    for idx in tools:
        t = tools[idx]
        try:
            name = t.GetAttrs().get("TOOLS_Name", "")
        except Exception:
            name = ""
        yield name, t

def _fusion_tool_names(comp):
    """Return the set-friendly list of tool names currently in the comp."""
    return [name for name, _ in _iter_fusion_tools(comp)]

def _fusion_set_point_input(tool, input_id, value):
    """Set a Fusion Point input (e.g. a mask Center).

    Point inputs do not accept a plain scalar; the fusionscript bridge variously
    accepts a 2-element list or a 1-indexed table depending on platform/version.
    Try the known encodings and report which one took (or the last error).
    """
    if isinstance(value, dict):
        candidates = [value]
    else:
        try:
            x, y = value[0], value[1]
        except (TypeError, KeyError, IndexError):
            return False, f"{input_id} must be [x, y] or {{1:x, 2:y}} (got {value!r})", None
        candidates = [[x, y], {1: x, 2: y}, {"1": x, "2": y}]
    last_err = None
    for cand in candidates:
        try:
            tool.SetInput(input_id, cand)
            return True, None, cand
        except Exception as exc:  # noqa: BLE401 - bridge raises bare exceptions
            last_err = str(exc)
    return False, last_err, None

def _fusion_add_mask(comp, p: Dict[str, Any]) -> Dict[str, Any]:
    """Add and configure a Rectangle/Ellipse mask in one call (issue #73).

    Equivalent to add_tool + a sequence of set_input calls, plus optional wiring
    of the mask into a downstream tool's mask input. Each input is applied
    independently so a single unsupported parameter does not abort the rest.
    """
    raw_type = str(p.get("mask_type", "Rectangle")).strip().lower()
    tool_type = _MASK_TOOL_ALIASES.get(raw_type)
    if not tool_type:
        return _err(
            "mask_type must be one of: Rectangle, Ellipse "
            f"(got {p.get('mask_type')!r})"
        )

    x = p.get("x", -1)
    y = p.get("y", -1)
    readback = bool(p.get("readback", True))

    comp.Lock()
    try:
        tool = comp.AddTool(tool_type, x, y)
        if not tool:
            return _err(
                f"Failed to add {tool_type}. Verify the comp is editable "
                "(switch to the Fusion page or target a clip with a Fusion comp)."
            )
        name = p.get("name")
        if name:
            tool.SetAttrs({"TOOLS_Name": str(name)})
        attrs = tool.GetAttrs() or {}
        tool_name = attrs.get("TOOLS_Name", "")

        results: List[Dict[str, Any]] = []

        # Center: accept center=[x,y]/{1:x,2:y}, or center_x / center_y.
        center = p.get("center")
        cx, cy = p.get("center_x"), p.get("center_y")
        if center is None and (cx is not None or cy is not None):
            center = [cx if cx is not None else 0.5, cy if cy is not None else 0.5]
        if center is not None:
            ok, err, applied = _fusion_set_point_input(tool, "Center", center)
            rec = {"input": "Center", "value": center, "success": ok}
            if not ok:
                rec["error"] = err
            elif readback:
                try:
                    rec["readback"] = _ser(tool.GetInput("Center"))
                except Exception as exc:
                    rec["readback_error"] = str(exc)
            results.append(rec)

        # Scalar inputs (friendly aliases) + any raw passthrough inputs.
        to_set: List[tuple] = []
        for friendly, fusion_id in _MASK_INPUT_ALIASES.items():
            if friendly in p:
                to_set.append((fusion_id, p[friendly]))
        raw_inputs = p.get("inputs")
        if isinstance(raw_inputs, dict):
            for k, v in raw_inputs.items():
                to_set.append((str(k), v))

        for fusion_id, value in to_set:
            rec = {"input": fusion_id, "value": value}
            try:
                tool.SetInput(fusion_id, value)
                rec["success"] = True
                if readback:
                    try:
                        rec["readback"] = _ser(tool.GetInput(fusion_id))
                    except Exception as exc:
                        rec["readback_error"] = str(exc)
            except Exception as exc:
                rec["success"] = False
                rec["error"] = str(exc)
            results.append(rec)

        out: Dict[str, Any] = {
            "success": True,
            "tool_name": tool_name,
            "tool_type": attrs.get("TOOLS_RegID", tool_type),
            "inputs_set": results,
        }

        # Optional wiring: connect this mask into a tool's mask input.
        connect_to = p.get("connect_to")
        if connect_to:
            input_name = p.get("connect_input", "EffectMask")
            target = comp.FindTool(str(connect_to))
            if not target:
                out["connection"] = {
                    "success": False,
                    "error": f"connect_to tool '{connect_to}' not found",
                }
            else:
                try:
                    ok = bool(target.ConnectInput(input_name, tool))
                    out["connection"] = {
                        "success": ok,
                        "target": str(connect_to),
                        "input_name": input_name,
                    }
                except Exception as exc:
                    out["connection"] = {"success": False, "error": str(exc)}
        return out
    finally:
        comp.Unlock()

def _fusion_find_text_tool(comp, p: Dict[str, Any]):
    """Find a Text+ (TextPlus) tool in the comp, or the named tool. (issue #73)"""
    name = p.get("tool_name")
    if name:
        tool = comp.FindTool(str(name))
        if not tool:
            return None, _err(f"Tool '{name}' not found")
        return tool, None
    # Auto-detect the first Text+ tool — this is what a Fusion title template
    # (e.g. "Deep") exposes its editable copy through.
    for name_, tool in _iter_fusion_tools(comp):
        try:
            reg = (tool.GetAttrs() or {}).get("TOOLS_RegID", "")
        except Exception:
            reg = ""
        if reg in ("TextPlus", "Text+") or "Text" in reg:
            return tool, None
    return None, _err(
        "No Text+ tool found in this comp. Pass tool_name explicitly, or call "
        "get_tool_list to inspect the node graph."
    )

def _fusion_set_text_plus(comp, p: Dict[str, Any]) -> Dict[str, Any]:
    """Set the text of a Fusion Text+ tool / title template. (issue #73)"""
    text = p.get("text")
    if not isinstance(text, str):
        return _err("set_text_plus requires params.text (string)")
    tool, err = _fusion_find_text_tool(comp, p)
    if err:
        return err
    input_id = p.get("input_name", "StyledText")
    readback = bool(p.get("readback", True))
    comp.Lock()
    try:
        try:
            tool.SetInput(input_id, text)
        except Exception as exc:
            return _err(f"SetInput({input_id!r}) failed: {exc}")
        out = {
            "success": True,
            "tool_name": (tool.GetAttrs() or {}).get("TOOLS_Name", ""),
            "input_name": input_id,
        }
        if readback:
            try:
                out["readback"] = _ser(tool.GetInput(input_id))
            except Exception as exc:
                out["readback_error"] = str(exc)
        return out
    finally:
        comp.Unlock()

def _fusion_get_text_plus(comp, p: Dict[str, Any]) -> Dict[str, Any]:
    """Read the text of a Fusion Text+ tool / title template. (issue #73)"""
    tool, err = _fusion_find_text_tool(comp, p)
    if err:
        return err
    input_id = p.get("input_name", "StyledText")
    try:
        val = tool.GetInput(input_id)
    except Exception as exc:
        return _err(f"GetInput({input_id!r}) failed: {exc}")
    return {
        "tool_name": (tool.GetAttrs() or {}).get("TOOLS_Name", ""),
        "input_name": input_id,
        "text": _ser(val),
    }

@mcp.tool()
def fusion_comp(action: str, params: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Fusion composition node graph operations.

    Target comp:
      - Timeline item: pass clip_id, timeline_item_id, or
        timeline_item={track_type, track_index, item_index}. Optional comp_name or
        1-based comp_index selects a specific comp; otherwise the first comp is used.
      - Fusion page: omit timeline scope and this uses Fusion().GetCurrentComp().

    Use timeline_item_fusion to add/delete/import/export comps on items.

    Actions:
      add_tool(tool_type, x?, y?, name?) -> {tool_name, tool_type}
      delete_tool(tool_name) -> {success}
      get_tool_list(type?) -> {tools, count}
      find_tool(name) -> {found, name, type, attrs}
      connect(target_tool, input_name, source_tool, output_name?) -> {success}
      disconnect(tool_name, input_name) -> {success}
      get_inputs(tool_name) -> {inputs}
      get_outputs(tool_name) -> {outputs}
      set_input(tool_name, input_name, value, time?) -> {success}
      get_input(tool_name, input_name, time?) -> {value}
      set_attrs(tool_name, attrs) -> {success}
      get_attrs(tool_name) -> {attrs}
      add_keyframe(tool_name, input_name, time, value) -> {success}
      get_keyframes(tool_name, input_name) -> {keyframes}
      delete_keyframe(tool_name, input_name, time) -> {success}
      get_comp_info() -> {name, tool_count, attrs}
      get_position(tool_name) -> {tool_name, x, y}  — read a node's FlowView position
      set_position(tool_name, x, y) -> {success, x, y, readback}  — move a node
      copy_tool(tool_name, name?, x?, y?) -> {success, new_tool, new_tools}  — duplicate a node
      auto_arrange(tool_names?, direction?, spacing?, x?, y?) -> {success, arranged, count}
        Lay tools out in a row (direction="horizontal", default) or column ("vertical").
      set_frame_range(start, end) -> {success}
      get_frame_range() -> {start, end}  — read the comp's render frame range
      render() -> {success}
      start_undo(name?) -> {success}
      end_undo(keep?) -> {success}
      bulk_set_inputs(ops) -> {results, op_count} — each op requires timeline scope plus tool_name, input_name, value
      bulk_set_expressions(ops) -> {results, op_count} — each op requires timeline scope plus tool_name, input_name, expression
      group_settings_export(group_name, path, include_advisory?) -> {path, published_inputs, input_count}
      group_settings_splice_inputs(source_path, template_path, dest_path?, source_group_name?, template_group_name?) -> {dest_path, summary}
        Replace a source .setting's `Inputs = ordered() { ... }` block with the matching block from template_path.
        Both files are read; neither GroupOperator is loaded into Resolve. Inner tools and outer structure are preserved.
      group_settings_load(group_name, settings_path, backup_path?, undo_name?) -> {settings_path, backup_path}
        Wraps the LoadSettings call in StartUndo/EndUndo + comp.Lock for reversibility.
      probe_group_published_inputs(group_name, settings_path?, max_inputs?, time?) -> {live_inputs, file_summary?}
      fusion_graph_capabilities(...) -> {supported, boundaries, common_tools}
      probe_fusion_comp(include_io?, max_tools?) -> {name, tool_count, tools}
      probe_fusion_tool(tool_name, include_io?) -> {found, tool}
      safe_add_tool(tool_type, name?, dry_run?) -> {success, tool}
      safe_set_inputs(tool_name, inputs, readback?) -> {success, results}
      safe_connect_tools(target_tool, input_name, source_tool, dry_run?) -> {success}
      fusion_boundary_report(include_io?) -> {capabilities, composition}
      add_fusion_mask(mask_type?, name?, center?|center_x?|center_y?, width?, height?,
        corner_radius?, angle?, soft_edge?, border_width?, invert?, inputs?, x?, y?,
        connect_to?, connect_input?, readback?) -> {success, tool_name, inputs_set, connection?}
        mask_type: "Rectangle" (default) or "Ellipse". One call = add the mask tool,
        set its params (corner_radius/width/height/center are 0..1), and optionally
        wire it into connect_to's mask input (connect_input default "EffectMask").
      set_text_plus(text, tool_name?, input_name?, readback?) -> {success, tool_name, readback?}
        Set the text of a Fusion Text+ tool / title template (e.g. a "Deep" Fusion
        title). Auto-finds the Text+ tool if tool_name is omitted; input_name
        defaults to "StyledText".
      get_text_plus(tool_name?, input_name?) -> {tool_name, input_name, text}

    Common tool_type values: Merge, Background, TextPlus, Transform, Blur,
      ColorCorrector, RectangleMask, EllipseMask, Tracker, MediaIn, MediaOut,
      Loader, Saver, Glow, FilmGrain, CornerPositioner, DeltaKeyer, UltraKeyer
    """
    p = params or {}

    if action == "bulk_set_inputs":
        return _fusion_comp_bulk_set_inputs(p)
    if action == "bulk_set_expressions":
        return _fusion_comp_bulk_set_expressions(p)
    if action == "group_settings_splice_inputs":
        return _fusion_group_settings_splice_inputs(p)

    comp, comp_err = _resolve_fusion_comp(p)
    if comp_err:
        return comp_err

    if action == "group_settings_export":
        return _fusion_group_settings_export(comp, p)
    if action == "group_settings_load":
        return _fusion_group_settings_load(comp, p)
    if action == "probe_group_published_inputs":
        return _fusion_probe_group_published_inputs(comp, p)

    if action == "fusion_graph_capabilities":
        return _fusion_graph_capabilities(comp)
    elif action == "probe_fusion_comp":
        return _fusion_comp_snapshot(comp, p)
    elif action == "probe_fusion_tool":
        return _probe_fusion_tool(comp, p)
    elif action == "safe_add_tool":
        return _safe_add_fusion_tool(comp, p)
    elif action == "safe_set_inputs":
        return _safe_set_fusion_inputs(comp, p)
    elif action == "safe_connect_tools":
        return _safe_connect_fusion_tools(comp, p)
    elif action == "fusion_boundary_report":
        return _fusion_boundary_report(comp, p)
    elif action == "add_fusion_mask":
        return _fusion_add_mask(comp, p)
    elif action == "set_text_plus":
        return _fusion_set_text_plus(comp, p)
    elif action == "get_text_plus":
        return _fusion_get_text_plus(comp, p)

    # --- Node Management ---
    if action == "add_tool":
        tool_type = p.get("tool_type")
        if not tool_type:
            return _err("tool_type is required (e.g. 'Merge', 'Transform', 'TextPlus', 'Background')")
        x = p.get("x", -1)
        y = p.get("y", -1)
        comp.Lock()
        try:
            tool = comp.AddTool(tool_type, x, y)
            if not tool:
                return _err(f"Failed to add tool '{tool_type}'. Check the tool ID is valid.")
            name = p.get("name")
            if name:
                tool.SetAttrs({"TOOLS_Name": name})
            attrs = tool.GetAttrs()
            return {"tool_name": attrs.get("TOOLS_Name", ""), "tool_type": attrs.get("TOOLS_RegID", tool_type)}
        finally:
            comp.Unlock()

    elif action == "delete_tool":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        comp.Lock()
        try:
            tool.Delete()
            return _ok()
        finally:
            comp.Unlock()

    elif action == "get_tool_list":
        filter_type = p.get("type")
        if filter_type:
            tools = comp.GetToolList(False, filter_type)
        else:
            tools = comp.GetToolList()
        result = []
        if tools:
            for idx in tools:
                t = tools[idx]
                attrs = t.GetAttrs()
                result.append({
                    "name": attrs.get("TOOLS_Name", ""),
                    "type": attrs.get("TOOLS_RegID", ""),
                })
        return {"tools": result, "count": len(result)}

    elif action == "find_tool":
        tool = comp.FindTool(p["name"])
        if not tool:
            return {"found": False}
        attrs = tool.GetAttrs()
        return {"found": True, "name": attrs.get("TOOLS_Name", ""), "type": attrs.get("TOOLS_RegID", ""), "attrs": _ser(attrs)}

    # --- Wiring ---
    elif action == "connect":
        target = comp.FindTool(p["target_tool"])
        if not target:
            return _err(f"Target tool '{p['target_tool']}' not found")
        source = comp.FindTool(p["source_tool"])
        if not source:
            return _err(f"Source tool '{p['source_tool']}' not found")
        comp.Lock()
        try:
            result = target.ConnectInput(p["input_name"], source)
            return {"success": bool(result)}
        finally:
            comp.Unlock()

    elif action == "disconnect":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        comp.Lock()
        try:
            result = tool.ConnectInput(p["input_name"], None)
            return {"success": bool(result)}
        finally:
            comp.Unlock()

    elif action == "get_inputs":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        input_list = tool.GetInputList()
        inputs = []
        if input_list:
            for idx in input_list:
                inp = input_list[idx]
                attrs = inp.GetAttrs()
                connected = inp.GetConnectedOutput()
                conn_info = None
                if connected:
                    conn_tool = connected.GetTool()
                    if conn_tool:
                        conn_info = conn_tool.GetAttrs().get("TOOLS_Name", "")
                inputs.append({
                    "name": attrs.get("INPS_Name", ""),
                    "id": attrs.get("INPS_ID", ""),
                    "type": attrs.get("INPS_DataType", ""),
                    "connected_to": conn_info,
                })
        return {"inputs": inputs}

    elif action == "get_outputs":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        output_list = tool.GetOutputList()
        outputs = []
        if output_list:
            for idx in output_list:
                out = output_list[idx]
                attrs = out.GetAttrs()
                outputs.append({
                    "name": attrs.get("OUTS_Name", ""),
                    "id": attrs.get("OUTS_ID", ""),
                    "type": attrs.get("OUTS_DataType", ""),
                })
        return {"outputs": outputs}

    # --- Parameters ---
    elif action == "set_input":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        comp.Lock()
        try:
            if "time" in p:
                tool.SetInput(p["input_name"], p["value"], p["time"])
            else:
                tool.SetInput(p["input_name"], p["value"])
            return _ok()
        finally:
            comp.Unlock()

    elif action == "get_input":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        if "time" in p:
            val = tool.GetInput(p["input_name"], p["time"])
        else:
            val = tool.GetInput(p["input_name"])
        return {"value": _ser(val)}

    elif action == "set_attrs":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        tool.SetAttrs(p["attrs"])
        return _ok()

    elif action == "get_attrs":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        return {"attrs": _ser(tool.GetAttrs())}

    # --- Keyframes ---
    elif action == "add_keyframe":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        comp.Lock()
        try:
            inp = tool[p["input_name"]]
            if not inp:
                return _err(f"Input '{p['input_name']}' not found on tool '{p['tool_name']}'")
            # Attach a BezierSpline modifier the first time this input is animated.
            # Without a spline, `inp[time] = value` only sets a STATIC value (the last
            # write wins) and never creates a keyframe. See the Fusion Scripting Guide.
            # Optional `modifier` lets callers pass e.g. "Path" for Point inputs.
            try:
                _already_animated = inp.GetConnectedOutput() is not None
            except Exception:
                _already_animated = False
            if not _already_animated:
                tool.AddModifier(p["input_name"], p.get("modifier", "BezierSpline"))
            tool[p["input_name"]][p["time"]] = p["value"]
            return _ok()
        finally:
            comp.Unlock()

    elif action == "get_keyframes":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        inp = tool[p["input_name"]]
        if not inp:
            return _err(f"Input '{p['input_name']}' not found on tool '{p['tool_name']}'")
        # GetKeyFrames() returns {1-based index: frame_position}, NOT
        # {time: value}. Iterating it directly puts the index in `time` and the
        # frame position in `value`. Read the actual keyframed value back from
        # the input at each frame position via GetInput.
        keyframes = []
        kfs = inp.GetKeyFrames()
        if kfs:
            for idx in sorted(kfs):
                frame = kfs[idx]
                value = tool.GetInput(p["input_name"], frame)
                keyframes.append({"time": frame, "value": _ser(value)})
        return {"keyframes": keyframes}

    elif action == "delete_keyframe":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        comp.Lock()
        try:
            inp = tool[p["input_name"]]
            if not inp:
                return _err(f"Input '{p['input_name']}' not found on tool '{p['tool_name']}'")
            inp.RemoveKeyFrame(p["time"])
            return _ok()
        finally:
            comp.Unlock()

    # --- Composition Control ---
    elif action == "get_comp_info":
        attrs = comp.GetAttrs()
        return {
            "name": attrs.get("COMPS_Name", ""),
            "tool_count": len(comp.GetToolList() or {}),
            "attrs": _ser(attrs),
        }

    elif action == "set_frame_range":
        comp.SetAttrs({"COMPN_RenderStartTime": p["start"], "COMPN_RenderEndTime": p["end"]})
        return _ok()

    elif action == "get_frame_range":
        attrs = comp.GetAttrs() or {}
        return {
            "start": attrs.get("COMPN_RenderStartTime"),
            "end": attrs.get("COMPN_RenderEndTime"),
        }

    elif action == "render":
        comp.Render()
        return _ok()

    elif action == "start_undo":
        comp.StartUndo(p.get("name", "MCP Operation"))
        return _ok()

    elif action == "end_undo":
        comp.EndUndo(p.get("keep", True))
        return _ok()

    # --- Node Layout (FlowView) ---
    elif action == "get_position":
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        flow = _fusion_flow_view(comp)
        if flow is None:
            return _err(
                "FlowView unavailable on this comp",
                code="FLOWVIEW_UNAVAILABLE", category="wrong_page",
                remediation="comp.CurrentFrame is only populated while the Fusion "
                             "page is active; call resolve.OpenPage('fusion') (or "
                             "switch pages in the UI) before get_position/set_position.",
            )
        pos = _parse_pos(flow.GetPosTable(tool))
        if pos is None:
            return _err(f"Could not read position for tool '{p['tool_name']}'")
        return {"tool_name": p["tool_name"], "x": pos[0], "y": pos[1]}

    elif action == "set_position":
        if "x" not in p or "y" not in p:
            return _err("set_position requires x and y")
        tool = comp.FindTool(p["tool_name"])
        if not tool:
            return _err(f"Tool '{p['tool_name']}' not found")
        flow = _fusion_flow_view(comp)
        if flow is None:
            return _err(
                "FlowView unavailable on this comp",
                code="FLOWVIEW_UNAVAILABLE", category="wrong_page",
                remediation="comp.CurrentFrame is only populated while the Fusion "
                             "page is active; call resolve.OpenPage('fusion') (or "
                             "switch pages in the UI) before get_position/set_position.",
            )
        x, y = float(p["x"]), float(p["y"])
        comp.Lock()
        try:
            flow.SetPos(tool, x, y)
        finally:
            comp.Unlock()
        # SetPos has no reliable return; confirm by reading the position back.
        pos = _parse_pos(flow.GetPosTable(tool))
        return {
            "success": True,
            "tool_name": p["tool_name"],
            "x": x,
            "y": y,
            "readback": {"x": pos[0], "y": pos[1]} if pos else None,
        }

    elif action == "copy_tool":
        src = comp.FindTool(p["tool_name"])
        if not src:
            return _err(f"Tool '{p['tool_name']}' not found")
        regid = src.GetAttrs().get("TOOLS_RegID")
        if not regid:
            return _err(f"Could not determine the tool type of '{p['tool_name']}'")
        # Duplicate by adding a same-type tool and loading the source's settings
        # through a temp .setting FILE. Passing SaveSettings()'s in-memory table
        # back into Paste/LoadSettings fails across the Python bridge; a file path
        # round-trips reliably. New node is found by diffing tool names.
        before = set(_fusion_tool_names(comp))
        fd, settings_path = tempfile.mkstemp(suffix=".setting")
        os.close(fd)
        new_tool = None
        comp.Lock()
        try:
            if not src.SaveSettings(settings_path):
                return _err(f"SaveSettings failed for '{p['tool_name']}'")
            new_tool = comp.AddTool(regid, -32768, -32768)
            if not new_tool:
                return _err(f"Failed to create a duplicate of '{p['tool_name']}'")
            new_tool.LoadSettings(settings_path)
        finally:
            comp.Unlock()
            try:
                os.remove(settings_path)
            except OSError:
                pass
        new_names = [n for n in _fusion_tool_names(comp) if n not in before]
        new_name = new_names[0] if new_names else new_tool.GetAttrs().get("TOOLS_Name", "")
        rename = p.get("name")
        if rename:
            comp.Lock()
            try:
                new_tool.SetAttrs({"TOOLS_Name": rename})
            finally:
                comp.Unlock()
            new_name = rename
        if "x" in p and "y" in p:
            flow = _fusion_flow_view(comp)
            if flow is not None:
                comp.Lock()
                try:
                    flow.SetPos(new_tool, float(p["x"]), float(p["y"]))
                finally:
                    comp.Unlock()
        return {
            "success": True,
            "source": p["tool_name"],
            "new_tool": new_name,
            "new_tools": new_names,
        }

    elif action == "auto_arrange":
        flow = _fusion_flow_view(comp)
        if flow is None:
            return _err(
                "FlowView unavailable on this comp",
                code="FLOWVIEW_UNAVAILABLE", category="wrong_page",
                remediation="comp.CurrentFrame is only populated while the Fusion "
                             "page is active; call resolve.OpenPage('fusion') (or "
                             "switch pages in the UI) before get_position/set_position.",
            )
        names = p.get("tool_names")
        if names:
            tools = [(n, comp.FindTool(n)) for n in names]
            tools = [(n, t) for n, t in tools if t]
        else:
            tools = list(_iter_fusion_tools(comp))
        if not tools:
            return _err("No tools to arrange")
        direction = (p.get("direction") or "horizontal").strip().lower()
        spacing = float(p.get("spacing", 2.0))
        x0, y0 = float(p.get("x", 0.0)), float(p.get("y", 0.0))
        arranged = []
        comp.Lock()
        try:
            for i, (name, tool) in enumerate(tools):
                if direction == "vertical":
                    x, y = x0, y0 + i * spacing
                else:
                    x, y = x0 + i * spacing, y0
                flow.SetPos(tool, x, y)
                arranged.append({"tool_name": name, "x": x, "y": y})
        finally:
            comp.Unlock()
        return {"success": True, "arranged": arranged, "count": len(arranged)}

    return _unknown(action, [
        "add_tool","delete_tool","get_tool_list","find_tool",
        "connect","disconnect","get_inputs","get_outputs",
        "set_input","get_input","set_attrs","get_attrs",
        "add_keyframe","get_keyframes","delete_keyframe",
        "get_comp_info","set_frame_range","get_frame_range","render",
        "start_undo","end_undo",
        "get_position","set_position","copy_tool","auto_arrange",
        "bulk_set_inputs",
        "bulk_set_expressions",
        "add_fusion_mask","set_text_plus","get_text_plus",
        *_FUSION_GROUP_KERNEL_ACTIONS,
        *_FUSION_KERNEL_ACTIONS,
    ])


_FUSION_GROUP_KERNEL_ACTIONS = [
    "group_settings_export",
    "group_settings_splice_inputs",
    "group_settings_load",
    "bulk_set_expressions",
    "probe_group_published_inputs",
]


_FUSION_KERNEL_ACTIONS = [
    "fusion_graph_capabilities",
    "probe_fusion_comp",
    "probe_fusion_tool",
    "safe_add_tool",
    "safe_set_inputs",
    "safe_connect_tools",
    "fusion_boundary_report",
]


_COMMON_FUSION_TOOLS = [
    "MediaIn",
    "MediaOut",
    "Background",
    "TextPlus",
    "Merge",
    "Transform",
    "Blur",
    "ColorCorrector",
    "RectangleMask",
    "EllipseMask",
    "Glow",
]


_MASK_TOOL_ALIASES = {
    "rectangle": "RectangleMask",
    "rect": "RectangleMask",
    "rectanglemask": "RectangleMask",
    "ellipse": "EllipseMask",
    "ellipsemask": "EllipseMask",
    "circle": "EllipseMask",
}


_MASK_INPUT_ALIASES = {
    "corner_radius": "CornerRadius",   # RectangleMask only
    "width": "Width",
    "height": "Height",
    "angle": "Angle",
    "soft_edge": "SoftEdge",
    "border_width": "BorderWidth",
    "invert": "Invert",
}
